const results = $input.first().json.results || [];
const db05_id = $('Extract DB05 ID').first().json.db05_id;
const sanitize = s => (s || '').toString()
  .replace(/[\/\\:<>#@\[\]\{\}\|\^\`\*_~"']/g, ' ')
  .replace(/[\u2010-\u2027\u2030-\u205E]/g, ' ')
  .replace(/[\uFF00-\uFF0F\uFF1A-\uFF20\uFF3B-\uFF40\uFF5B-\uFF65]/g, ' ')
  .replace(/[\u3000-\u3017\u301D-\u303F]/g, ' ')
  .replace(/\s+/g, ' ').trim().slice(0, 1500);
const total = results.length;
const done = results.filter(p => (p.properties['ai狀態']?.status?.name||'') === '完成').length;
const pending = results.filter(p => (p.properties['ai狀態']?.status?.name||'') !== '完成');
if (pending.length === 0) {
  return [{ json: { none: true, flow_id: db05_id, tg_message: '此 DB05 沒有待執行的棒次 (全套 ' + total + ' 棒已全部完成)', cb_ok: 'noop', cb_all: 'noop' } }];
}
const p = pending[0];
const db06_id = p.id.replace(/-/g, '');
const ai_mode = sanitize(p.properties['ai模式']?.select?.name || '');
const sort_num = p.properties['排序']?.number;
const exec_idea = p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '';
const idea_show = exec_idea ? sanitize(exec_idea) : '(執行構想為空,將用該棒預設工作指示)';
const msg = '關卡A 執行前確認\n' +
  '第 ' + (sort_num != null ? sort_num : '?') + ' 棒 (' + ai_mode + ')。全套 ' + total + ' 棒,已完成 ' + done + ' 棒。\n' +
  'DB06 頁面 ' + db06_id + '\n\n' +
  '本棒預定執行構想:\n' + idea_show + '\n\n' +
  '按 OK 放行這一關,按 OK ALL 之後全自動。要改執行構想 skip stop 請打字 reply。\n' +
  'gateA db06=' + db06_id;
return [{ json: { none: false, db06_id, flow_id: db05_id, tg_message: msg, cb_ok: 'A1:' + db06_id, cb_all: 'AA:' + db06_id } }];

const msg_id = ($input.first().json.result?.message_id || '').toString();
const flow_id = $('Pick first pending').first().json.flow_id;
return [{ json: { flow_id, last_msg_id: msg_id } }];
